import{c as e,Q as d,j as n,m as r}from"./chunks/framework.BPKcPtvA.js";const x=JSON.parse('{"title":"Tier matrix","description":"Which tools are allowed in which tier.","frontmatter":{"title":"Tier matrix","description":"Which tools are allowed in which tier."},"headers":[],"relativePath":"reference/tier-matrix.md","filePath":"reference/tier-matrix.md","lastUpdated":1778951051000}'),s={name:"reference/tier-matrix.md"};function a(i,t,l,o,c,y){return d(),n("div",null,[...t[0]||(t[0]=[r('<h1 id="tier-matrix" tabindex="-1">Tier matrix <a class="header-anchor" href="#tier-matrix" aria-label="Permalink to &quot;Tier matrix&quot;">​</a></h1><p>A quick lookup table for whether a given tool runs in each of the four tiered-autonomy states.</p><table tabindex="0"><thead><tr><th>Tool</th><th style="text-align:center;">Advisory</th><th style="text-align:center;">Confirm-per-action</th><th style="text-align:center;">Policy-bound</th><th style="text-align:center;">Paused</th></tr></thead><tbody><tr><td><code>read.*</code> (all 7)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>position.buy</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ if within bounds</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>position.sell</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ if within bounds</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>position.claim</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ always (claim is fee-bearing pull)</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>position.rebalance</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ if within drift bounds</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>policy.set_tier</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ passkey (requires re-auth)</td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">❌ — except <code>→ resume</code>, which needs passkey</td></tr><tr><td><code>policy.pause</code></td><td style="text-align:center;">✅ idempotent</td><td style="text-align:center;">✅ idempotent</td><td style="text-align:center;">✅ idempotent</td><td style="text-align:center;">✅ idempotent (no-op)</td></tr><tr><td><code>policy.audit_export</code></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>policy.session_key_status</code></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>issuer.distribute_yield</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ if within issuer-side bounds</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>issuer.kyc_add</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ if within bounds</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>issuer.kyc_remove</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅ if within bounds</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>issuer.unpause_token</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>issuer.audit_query</code></td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td><code>governance.propose</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌ 423</td></tr><tr><td><code>governance.cast_vote</code></td><td style="text-align:center;">✅ passkey</td><td style="text-align:center;">✅ session key</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌ 423</td></tr></tbody></table><p><strong>Legend:</strong></p><ul><li>✅ <strong>passkey</strong> — Action signed by your master passkey via WebAuthn ceremony.</li><li>✅ <strong>session key</strong> — Action signed by your scoped session key (no WebAuthn re-prompt for ~1h).</li><li>✅ <strong>if within bounds</strong> — Cron policy engine signs automatically if the encrypted threshold check passes; on breach, auto-pauses to Advisory.</li><li>✅ <strong>idempotent</strong> — Always allowed regardless of state.</li><li>❌ <strong>423</strong> — Returns <code>423 PAUSED</code>. Read tools still work.</li></ul><h2 id="tier-transition-matrix" tabindex="-1">Tier transition matrix <a class="header-anchor" href="#tier-transition-matrix" aria-label="Permalink to &quot;Tier transition matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>From → To</th><th style="text-align:center;">Allowed</th><th>Signer required</th></tr></thead><tbody><tr><td>Advisory → Confirm-per-action</td><td style="text-align:center;">✅</td><td>Passkey (signs new session-key validator install)</td></tr><tr><td>Advisory → Policy-bound</td><td style="text-align:center;">✅</td><td>Passkey + encrypted threshold setup</td></tr><tr><td>Advisory → Paused</td><td style="text-align:center;">✅</td><td>None (always allowed)</td></tr><tr><td>Confirm-per-action → Advisory</td><td style="text-align:center;">✅</td><td>Passkey (uninstalls validator)</td></tr><tr><td>Confirm-per-action → Policy-bound</td><td style="text-align:center;">✅</td><td>Passkey + encrypted threshold setup</td></tr><tr><td>Confirm-per-action → Paused</td><td style="text-align:center;">✅</td><td>None</td></tr><tr><td>Policy-bound → Advisory</td><td style="text-align:center;">✅</td><td>Passkey (clears thresholds; uninstalls cron-engine binding)</td></tr><tr><td>Policy-bound → Confirm-per-action</td><td style="text-align:center;">✅</td><td>Passkey (clears thresholds)</td></tr><tr><td>Policy-bound → Paused</td><td style="text-align:center;">✅ auto on breach</td><td>None (manual) or auto (on breach)</td></tr><tr><td>Paused → Advisory</td><td style="text-align:center;">✅</td><td>Passkey (reinstalls session-key validator)</td></tr><tr><td>Paused → Confirm-per-action</td><td style="text-align:center;">✅</td><td>Passkey</td></tr><tr><td>Paused → Policy-bound</td><td style="text-align:center;">✅</td><td>Passkey + threshold setup</td></tr></tbody></table><h2 id="breach-→-auto-pause" tabindex="-1">Breach → auto-pause <a class="header-anchor" href="#breach-→-auto-pause" aria-label="Permalink to &quot;Breach → auto-pause&quot;">​</a></h2><p>A Policy-bound breach (any of: max drawdown, daily spend, min yield, drift tolerance) triggers an auto-pause. The cascade and reasoning live in <a href="/policy/tiered-autonomy#policy-bound-the-automation-tier">Tiered autonomy → Policy-bound</a>.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/policy/tiered-autonomy">Tiered autonomy</a> — what each tier means.</li><li><a href="/reference/tool-catalog">Tool catalog</a> — what each tool does.</li><li><a href="/policy/pause">The /pause kill-switch</a> — the always-on escape hatch.</li></ul>',11)])])}const h=e(s,[["render",a]]);export{x as __pageData,h as default};
